  5	  EmptyState,
  6	  EmptyStateBody,
  7	  EmptyStateIcon,
  8	  EmptyStateVariant,
  9	  EmptyStateHeader,
 10	  EmptyStateFooter
 11	} from '@patternfly/react-core';
 12	import { kialiStyle } from 'styles/StyleUtils';
 13	import * as _ from 'lodash';
 14	import { Namespace } from '../../types/Namespace';
 15	import { KialiIcon } from '../../config/KialiIcon';
 16	import { DecoratedGraphElements } from '../../types/Graph';
 17	import { RefreshIntervalManual } from 'config/Config';
 18	import { IntervalInMilliseconds } from 'types/Common';
 19	import { t } from 'utils/I18nUtils';
 20	import { RunMode } from 'types/ServerConfig';
 21	import { serverConfig } from 'config';
 22	
 23	type EmptyGraphLayoutProps = {
 24	  action?: any;
 25	  elements?: DecoratedGraphElements;
 26	  error?: string;
 27	  isError: boolean;
 28	  isLoading?: boolean;
 29	  isMiniGraph: boolean;
 30	  loaded: boolean;
 31	  namespaces?: Namespace[];
 32	  refreshInterval?: IntervalInMilliseconds;
 33	  showIdleNodes?: boolean;
 34	  toggleIdleNodes?: () => void;
 35	};
 36	
 37	const emptyStateStyle = kialiStyle({
 38	  height: '98%',
 39	  marginRight: 'auto',
 40	  marginLeft: 'auto',
 41	  marginBottom: 10,
 42	  marginTop: 10
 43	});
 44	
 45	type EmptyGraphLayoutState = {};
 46	
 47	export class EmptyGraphLayout extends React.Component<EmptyGraphLayoutProps, EmptyGraphLayoutState> {
 48	  shouldComponentUpdate(nextProps: EmptyGraphLayoutProps): boolean {
 49	    const currentIsEmpty = this.props.elements === undefined || _.isEmpty(this.props.elements.nodes);
 50	    const nextIsEmpty = nextProps.elements === undefined || _.isEmpty(nextProps.elements.nodes);
 51	
 52	    // Update if we have elements and we are not loading
 53	    if (!nextProps.isLoading && !nextIsEmpty) {
 54	      return true;
 55	    }
 56	
 57	    // Update if we are going from having no elements to having elements or vice versa
 58	    if (currentIsEmpty !== nextIsEmpty) {
 59	      return true;
 60	    }
 61	    // Do not update if we have elements and the namespace didn't change, as this means we are refreshing
 62	    return !(!nextIsEmpty && _.isEqual(this.props.namespaces, nextProps.namespaces));
 63	  }
 64	
 65	  namespacesText(): React.ReactElement | null {
 66	    if (this.props.namespaces && this.props.namespaces.length > 0) {
 67	      if (this.props.namespaces.length === 1) {
 68	        return (
 69	          <div>
 70	            <b>{this.props.namespaces[0].name}</b>
 71	          </div>
 72	        );
 73	      } else {
 74	        const namespacesString = `${this.props.namespaces
 75	          .slice(0, -1)
 76	          .map(namespace => namespace.name)
 77	          .join(',')} and ${this.props.namespaces[this.props.namespaces.length - 1].name}`;
 78	        return (
 79	          <div>
 80	            <b>{namespacesString}</b>
 81	          </div>
 82	        );
 83	      }
 84	    }
 85	    return null;
 86	  }
 87	
 88	  render(): React.ReactNode {
 89	    if (this.props.isError) {
 90	      return (
 91	        <EmptyState id="empty-graph-error" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
 92	          <EmptyStateHeader
 93	            titleText={t('Error loading graph')}
 94	            icon={<EmptyStateIcon icon={KialiIcon.Error} />}
 95	            headingLevel="h5"
 96	          />
 97	          <EmptyStateBody>{this.props.error}</EmptyStateBody>
 98	        </EmptyState>
 99	      );
100	    }
101	
102	    if (this.props.isLoading) {
103	      return (
104	        <EmptyState id="empty-graph-is-loading" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
105	          <EmptyStateHeader titleText={t('Loading graph')} headingLevel="h5" />
106	        </EmptyState>
107	      );
108	    }
109	
110	    const isGraphEmpty = !this.props.elements || !this.props.elements.nodes || this.props.elements.nodes.length < 1;
111	
112	    if (this.props.namespaces?.length === 0) {
113	      return (
114	        <EmptyState id="empty-graph-no-namespace" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
115	          <EmptyStateHeader titleText={t('No namespace is selected')} headingLevel="h5" />
116	          <EmptyStateBody>
117	            {t('There is currently no namespace selected, please select one using the Namespace selector.')}
118	          </EmptyStateBody>
119	        </EmptyState>
120	      );
121	    }
122	
123	    if (this.props.refreshInterval === RefreshIntervalManual && !this.props.loaded && !this.props.isMiniGraph) {
124	      return (
125	        <EmptyState
126	          id="empty-graph-manual"
127	          data-test="manual-refresh"
128	          variant={EmptyStateVariant.lg}
129	          className={emptyStateStyle}
130	        >
131	          <EmptyStateHeader titleText={t('Manual refresh required')} headingLevel="h5" />
132	          <EmptyStateBody>
133	            {t(
134	              'The refresh interval is set to "Manual". To render the graph, select your desired filters and options and then click the Refresh button. Or, if preferred, change the setting to the desired interval.'
135	            )}
136	          </EmptyStateBody>
137	        </EmptyState>
138	      );
139	    }
140	
141	    if (isGraphEmpty && !this.props.isMiniGraph) {
142	      return (
143	        <EmptyState id="empty-graph" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
144	          <EmptyStateHeader titleText={t('Empty Graph')} headingLevel="h5" />
145	          <EmptyStateBody>
146	            {t(
147	              'There is currently no graph available for the selected namespaces. This usually means the namespaces do not have measurable traffic for the selected time period:'
148	            )}
149	            {this.namespacesText()}
150	            <br />
151	            {this.props.showIdleNodes && (
152	              <>
153	                {t(
154	                  'You are currently displaying "Idle nodes". Send requests to the service mesh and click the Refresh button.'
155	                )}
156	              </>
157	            )}
158	            {!this.props.showIdleNodes && (
159	              <>{t('You can enable "Idle Nodes" to display nodes that have yet to see any request traffic.')}</>
160	            )}
161	            <p>
162	              <br />
163	              {t('To read the FAQ entry about why your graph may be empty, ')}
164	              <a href={'https://kiali.io/docs/faq/graph/#emptygraph'} target="_blank" rel="noreferrer">
165	                {t('click here.')}
166	              </a>
167	            </p>
168	          </EmptyStateBody>
169	          <EmptyStateFooter>
170	            <Button
171	              onClick={this.props.showIdleNodes ? this.props.action : this.props.toggleIdleNodes}
172	              variant={ButtonVariant.primary}
173	            >
174	              {(this.props.showIdleNodes && <>{t('Refresh')}</>) || <>{t('Display idle nodes')}</>}
175	            </Button>
176	          </EmptyStateFooter>
177	        </EmptyState>
178	      );
179	    }
180	
181	    // TODO: Implement minigraph in offline mode.
182	    if (this.props.isMiniGraph && serverConfig.runMode === RunMode.OFFLINE) {
183	      return (
184	        <EmptyState
185	          id="empty-mini-graph"
186	          data-test="minigraph-offline"
187	          variant={EmptyStateVariant.lg}
188	          className={emptyStateStyle}
189	        >
190	          <EmptyStateHeader
191	            titleText={
192	              <>
193	                <KialiIcon.Offline /> {t('offline')}
194	              </>
195	            }
196	            headingLevel="h5"
197	          />
198	          <EmptyStateBody>{t('Minigraph is currently unavailable offline.')}</EmptyStateBody>
199	        </EmptyState>
200	      );
201	    }
202	
203	    if (isGraphEmpty && this.props.isMiniGraph) {
204	      return (
205	        <EmptyState id="empty-mini-graph" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
206	          <EmptyStateHeader titleText={t('Empty Graph')} headingLevel="h5" />
207	          <EmptyStateBody>{t('No graph traffic for the time period.')}</EmptyStateBody>
208	        </EmptyState>
209	      );
210	    }
211	
212	    return this.props.children;
213	  }
214	}

